#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>
#include <limits>

// Assume the user's Date class is available here

int main() {
    int d, m, y;
    std::string method_call;
    while (std::cin >> d >> m >> y >> method_call) {
        Date date(d, m, y);
        if (method_call == "isValidDate") {
            std::cout << (date.isValidDate() ? "true" : "false") << std::endl;
        } else if (method_call == "displayDate") {
            std::stringstream buffer;
            std::streambuf* old_cout = std::cout.rdbuf(buffer.rdbuf());
            date.displayDate();
            std::cout.rdbuf(old_cout);
            std::cout << buffer.str() << std::endl;
        }
    }
    return 0;
}
